class Solution {
    public int findTheLongestSubstring(String s) {
        int n = s.length();
        int res = 0;
        int[] count = new int[1 << 5];
        count[0] = 1;
        int mask = 0;
        for (int i = 0; i < n; i++) {
            char c = s.charAt(i);
            if (c == 'a') mask ^= 1;
            else if (c == 'e') mask ^= 2;
            else if (c == 'i') mask ^= 4;
            else if (c == 'o') mask ^= 8;
            else if (c == 'u') mask ^= 16;
            res = Math.max(res, i + 1 - (count[mask] == 0 ? n : count[mask]));
            count[mask]++;
        }
        return res;
    }
}
